import requests
import json

class NewspaperSummaryApp:
    def __init__(self):
        self.api_key = "YOUR_API_KEY"
        self.api_url = "https://api.claude.ai/summarize"

    def get_newspaper_title(self):
        return input("Enter the title of the newspaper you would like to summarize: ")

    def get_newspaper_text(self):
        return input("Enter the text of the newspaper you would like to summarize: ")

    def call_api(self, text):
        headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json"
        }
        data = {
            "text": text,
            "summary_length": 100
        }
        response = requests.post(self.api_url, headers=headers, data=json.dumps(data))
        if response.status_code == 200:
            return response.json()["summary"]
        else:
            return None

    def ask_question(self, summary):
        print("Here is a summary of the newspaper: ")
        print(summary)
        question = input("Do you have any questions about the summary? (yes/no): ")
        if question.lower() == "yes":
            ask_again = True
            while ask_again:
                question = input("Enter your question: ")
                response = requests.post(self.api_url, headers={"Authorization": f"Bearer {self.api_key}", "Content-Type": "application/json"}, data=json.dumps({"text": question, "summary_length": 100}))
                if response.status_code == 200:
                    print(response.json()["summary"])
                ask_again = input("Do you have another question? (yes/no): ").lower() == "yes"
        else:
            print("Thank you for using the newspaper summary app.")

    def run(self):
        newspaper_title = self.get_newspaper_title()
        newspaper_text = self.get_newspaper_text()
        summary = self.call_api(newspaper_text)
        if summary is not None:
            self.ask_question(summary)
        else:
            print("Failed to retrieve summary.")

if __name__ == "__main__":
    app = NewspaperSummaryApp()
    app.run()

